import scala.util.Random
import java.security.SecureRandom
import java.time.Instant
import java.util.concurrent.ConcurrentHashMap
import scala.jdk.CollectionConverters._

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant
)

case class ApiKey(
  key: String,
  name: String,
  createdAt: Instant,
  isActive: Boolean
)

class TokenGenerationService {
  private val secureRandom = new SecureRandom()
  private val sessions = new ConcurrentHashMap[String, SessionToken]()
  private val apiKeys = new ConcurrentHashMap[String, ApiKey]()
  
  private val SESSION_TOKEN_LENGTH = 64
  private val API_KEY_LENGTH = 64
  private val SESSION_DURATION_SECONDS = 3600L
  
  private def generateSecureToken(length: Int): String = {
    val chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_"
    val bytes = new Array[Byte](length)
    secureRandom.nextBytes(bytes)
    bytes.map(b => chars.charAt(Math.abs(b.toInt) % chars.length)).mkString
  }
  
  def generateSessionToken(userId: String): SessionToken = {
    val token = generateSecureToken(SESSION_TOKEN_LENGTH)
    val now = Instant.now()
    val expiresAt = now.plusSeconds(SESSION_DURATION_SECONDS)
    
    val sessionToken = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt
    )
    
    sessions.put(token, sessionToken)
    sessionToken
  }
  
  def generateApiKey(name: String): ApiKey = {
    val key = generateSecureToken(API_KEY_LENGTH)
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      name = name,
      createdAt = now,
      isActive = true
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }
  
  def validateSessionToken(token: String): Option[SessionToken] = {
    Option(sessions.get(token)).filter { session =>
      session.expiresAt.isAfter(Instant.now())
    }
  }
  
  def validateApiKey(key: String): Option[ApiKey] = {
    Option(apiKeys.get(key)).filter(_.isActive)
  }
  
  def revokeSessionToken(token: String): Boolean = {
    sessions.remove(token) != null
  }
  
  def revokeApiKey(key: String): Boolean = {
    Option(apiKeys.get(key)) match {
      case Some(apiKey) =>
        apiKeys.put(key, apiKey.copy(isActive = false))
        true
      case None => false
    }
  }
  
  def refreshSessionToken(token: String): Option[SessionToken] = {
    validateSessionToken(token).map { session =>
      sessions.remove(token)
      generateSessionToken(session.userId)
    }
  }
  
  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessions.asScala.filter { case (_, session) =>
      session.expiresAt.isBefore(now)
    }.keys.toList
    
    expired.foreach(sessions.remove)
    expired.size
  }
  
  def getActiveSessionsForUser(userId: String): List[SessionToken] = {
    val now = Instant.now()
    sessions.asScala.values.filter { session =>
      session.userId == userId && session.expiresAt.isAfter(now)
    }.toList
  }
  
  def revokeAllUserSessions(userId: String): Int = {
    val userSessions = getActiveSessionsForUser(userId)
    userSessions.foreach(session => sessions.remove(session.token))
    userSessions.size
  }
  
  def getApiKeysByName(name: String): List[ApiKey] = {
    apiKeys.asScala.values.filter(_.name == name).toList
  }
  
  def getAllActiveApiKeys(): List[ApiKey] = {
    apiKeys.asScala.values.filter(_.isActive).toList
  }
}

object TokenGenerationService {
