  }
  
  def refreshSession(token: String): Option[String] = {
    tokenService.refreshSessionToken(token).map(_.token)
  }
  
  def endAllUserSessions(userId: String): Int = {
    tokenService.revokeAllUserSessions(userId)
  }
}

class ApiKeyManager(tokenService: TokenGenerationService) {
  
